import { useState } from "react";
import "./sidebar.css";
import {
  LineStyle,
  Timeline,
  TrendingUp,
  PermIdentity,
  Storefront,
  AttachMoney,
  BarChart,
  MailOutline,
  DynamicFeed,
  ChatBubbleOutline,
  WorkOutline,
  Report
} from "@material-ui/icons";
import { Link, NavLink, useLocation } from "react-router-dom";
import { useTranslation } from "react-i18next";
import i18next from "i18next";


export default function Sidebar() {
  const { i18n, t } = useTranslation(["sidebar"]);
  const location = useLocation();

  const isActive = (pathname) => {
    return location.pathname === pathname;
  };

  return (
    <div className="sidebar">
      <div className="sidebarWrapper">
        <div className="sidebarMenu">
          <h3 className="sidebarTitle">{t("dashboard")}</h3>
          <ul className="sidebarList">
            <NavLink to="/" className="sidebarListItem" isActive={() => isActive("/")}>
                <LineStyle className="sidebarIcon" />
                {t("home")}
            </NavLink>
            <NavLink to="/analytics" className="sidebarListItem" isActive={() => isActive("/analytics")}>
              <Timeline className="sidebarIcon" />
              {t("analytics")}
            </NavLink>
            <NavLink to="/sales" className="sidebarListItem" isActive={() => isActive("/sales")}>
                <TrendingUp className="sidebarIcon" />
                {t("sales")}
            </NavLink>
            <NavLink to="/orders" className="sidebarListItem" isActive={() => isActive("/orders")}>
                <TrendingUp className="sidebarIcon" />
                {t("orders")}
            </NavLink>
          </ul>
        </div>
        <div className="sidebarMenu">
          <h3 className="sidebarTitle">{t("quickMenu")}</h3>
          <ul className="sidebarList">
            <NavLink to="/users" className="sidebarListItem" isActive={() => isActive("/users")}>
                <PermIdentity className="sidebarIcon" />
                {t("users")}
            </NavLink>
            <NavLink to="/products" className="sidebarListItem" isActive={() => isActive("/products")}>
                <Storefront className="sidebarIcon" />
                {t("products")}
            </NavLink>
            <NavLink to="/transactions" className="sidebarListItem" isActive={() => isActive("/transactions")}>
              <AttachMoney className="sidebarIcon" />
              {t("transactions")}
            </NavLink>
            <NavLink to="/reports" className="sidebarListItem" isActive={() => isActive("/reports")}>
              <BarChart className="sidebarIcon" />
              {t("reports")}
              </NavLink>
          </ul>
        </div>
        <div className="sidebarMenu">
          <h3 className="sidebarTitle">{t("notifications")}</h3>
          <ul className="sidebarList">
            <NavLink to="/mail" className="sidebarListItem" isActive={() => isActive("/mail")}>
              <MailOutline className="sidebarIcon" />
              {t("mail")}
            </NavLink>
            <NavLink to="/feedback" className="sidebarListItem" isActive={() => isActive("/feedback")}>
              <DynamicFeed className="sidebarIcon" />
              {t("feedback")}
            </NavLink>
            <NavLink to="/messages" className="sidebarListItem" isActive={() => isActive("/messages")}>
              <ChatBubbleOutline className="sidebarIcon" />
              {t("messages")}
            </NavLink>
          </ul>
        </div>
        <div className="sidebarMenu">
          <h3 className="sidebarTitle">{t("staff")}</h3>
          <ul className="sidebarList">
            <NavLink to="/manage" className="sidebarListItem" isActive={() => isActive("/manage")}>
              <WorkOutline className="sidebarIcon" />
              {t("manage")}
              </NavLink>
            <NavLink to="/staff_analytics" className="sidebarListItem" isActive={() => isActive("/staff_analytics")}>
              <Timeline className="sidebarIcon" />
              {t("analytics")}
            </NavLink>
            <NavLink to="/staff_reports" className="sidebarListItem" isActive={() => isActive("/staff-reports")}>
              <Report className="sidebarIcon" />
              {t("reports")}
            </NavLink>
          </ul>
        </div>
      </div>
    </div>
  );
}
